def descriptor(rA, rB, rX, nA, nB, nX):
    # New descriptor: measures mismatch of ionic radii scaled by the geometric mean of oxidation states
    import math
    size_mismatch = abs(rA - rX) + abs(rB - rX)
    oxidation_scale = math.sqrt(abs(nA) * abs(nB))
    return size_mismatch / (oxidation_scale + 1e-8)

