def descriptor(rA, rB, rX, nA, nB, nX):
    size_ratio = rA / rX
    charge_ratio = abs(nA / nX)
    size_difference = abs(rA - rB) / rX
    stability_indicator = (size_ratio * (1 - size_difference)) / (charge_ratio + 1e-6)
    return float(stability_indicator)

def descriptor(rA, rB, rX, nA, nB, nX):
    import math
    # Calculate the normalized size mismatch between A and X
    denom_size = rA + rX
    size_mismatch = abs(rA - rX) / denom_size if denom_size != 0 else 0.0

    # Calculate the charge imbalance ratio
    if nX != 0:
        charge_ratio = abs(nA / nX)
    else:
        charge_ratio = 0.0

    # Incorporate the ionic packing efficiency based on B and X radii ratio
    denom_n = nB + nX
    if denom_n != 0:
        packing_efficiency = (rB / rX) * (abs(nB - nX) / denom_n)
    else:
        packing_efficiency = 0.0

    # Combine effects: size mismatch dominates but adjusted by charge and packing
    return size_mismatch * (1 + charge_ratio) * (1 + packing_efficiency)
